PRAGMA foreign_keys=OFF;
BEGIN TRANSACTION;
CREATE TABLE users (
	id INTEGER NOT NULL, 
	name VARCHAR, 
	email VARCHAR NOT NULL, 
	hashed_password VARCHAR NOT NULL, 
	role VARCHAR, 
	created_at DATETIME, 
	updated_at DATETIME, 
	username VARCHAR, 
	full_name VARCHAR, base_load_hours_per_week REAL DEFAULT 0.0, 
	PRIMARY KEY (id)
);
CREATE TABLE projects (
	id INTEGER NOT NULL, 
	name VARCHAR NOT NULL, 
	description TEXT, 
	start_date DATETIME, 
	end_date DATETIME, 
	budget FLOAT, 
	status VARCHAR(11), 
	priority VARCHAR(8), 
	display_status VARCHAR NOT NULL, 
	color VARCHAR, 
	created_at DATETIME, 
	updated_at DATETIME, 
	PRIMARY KEY (id)
);
CREATE TABLE groups (
	id INTEGER NOT NULL, 
	name VARCHAR NOT NULL, 
	description TEXT, 
	type VARCHAR(16), 
	created_at DATETIME, 
	updated_at DATETIME, start_date DATETIME, end_date DATETIME, 
	PRIMARY KEY (id)
);
CREATE TABLE tasks (
	id INTEGER NOT NULL, 
	project_id INTEGER, 
	name VARCHAR NOT NULL, 
	description TEXT, 
	assigned_to INTEGER, 
	due_date DATETIME, 
	status VARCHAR(11), 
	priority VARCHAR(6), 
	type VARCHAR(13), 
	start_date DATETIME, 
	progress INTEGER, 
	cost FLOAT, 
	"dependsOn" JSON, 
	"shotID" VARCHAR, 
	"seqID" VARCHAR, 
	created_at DATETIME, 
	display_status VARCHAR NOT NULL, 
	updated_at DATETIME, phases JSON, auto_started BOOLEAN DEFAULT 0, auto_delayed BOOLEAN DEFAULT 0, deliverables TEXT, check_items JSON, 
	PRIMARY KEY (id), 
	FOREIGN KEY(project_id) REFERENCES projects (id), 
	FOREIGN KEY(assigned_to) REFERENCES users (id)
);
