CREATE TABLE events (
	id INTEGER NOT NULL, 
	project_id INTEGER, 
	title VARCHAR NOT NULL, 
	description TEXT, 
	start_time DATETIME NOT NULL, 
	end_time DATETIME NOT NULL, 
	location VARCHAR, 
	type VARCHAR(9) NOT NULL, 
	"allDay" BOOLEAN, 
	participants JSON, 
	status VARCHAR NOT NULL, 
	created_at DATETIME, 
	updated_at DATETIME, 
	PRIMARY KEY (id), 
	FOREIGN KEY(project_id) REFERENCES projects (id)
);
