CREATE TABLE user_groups (
	user_id INTEGER NOT NULL, 
	group_id INTEGER NOT NULL, 
	role VARCHAR(8), 
	created_at DATETIME, 
	updated_at DATETIME, 
	PRIMARY KEY (user_id, group_id), 
	FOREIGN KEY(user_id) REFERENCES users (id), 
	FOREIGN KEY(group_id) REFERENCES groups (id)
);
CREATE TABLE task_status_history (
	id INTEGER NOT NULL, 
	task_id INTEGER NOT NULL, 
	status VARCHAR(11) NOT NULL, 
	changed_at DATETIME NOT NULL, 
	changed_by INTEGER, 
	PRIMARY KEY (id), 
	FOREIGN KEY(task_id) REFERENCES tasks (id), 
	FOREIGN KEY(changed_by) REFERENCES users (id)
);
CREATE TABLE tasks_backup(
  id INT,
  project_id INT,
  name TEXT,
  description TEXT,
  assigned_to INT,
  due_date NUM,
  status TEXT,
  priority TEXT,
  type TEXT,
  start_date NUM,
  progress INT,
  cost REAL,
  dependsOn NUM,
  shotID TEXT,
  seqID TEXT,
  created_at NUM,
  display_status TEXT,
  updated_at NUM
);
CREATE TABLE tasks_new (
                id INTEGER PRIMARY KEY,
                project_id INTEGER,
                name VARCHAR NOT NULL,
                description TEXT,
                assigned_to INTEGER,
                due_date DATETIME,
                status VARCHAR,
                priority VARCHAR,
                type VARCHAR,
                start_date DATETIME,
                progress INTEGER,
                cost FLOAT,
                "dependsOn" JSON,
                "shotID" VARCHAR,
                "seqID" VARCHAR,
                created_at DATETIME,
                display_status VARCHAR DEFAULT 'online',
                updated_at DATETIME,
                FOREIGN KEY(project_id) REFERENCES projects(id),
                FOREIGN KEY(assigned_to) REFERENCES users(id)
            );
CREATE TABLE notes (
	id INTEGER NOT NULL, 
	title VARCHAR, 
	content TEXT, 
	image_urls JSON, 
	created_by INTEGER, 
	created_at DATETIME, 
	updated_at DATETIME, project_id INTEGER, image_positions TEXT, content_position JSON, text_boxes JSON, pdf_urls TEXT, pdf_positions TEXT, audio_urls JSON, audio_positions JSON, 
	PRIMARY KEY (id), 
	FOREIGN KEY(created_by) REFERENCES users (id)
);
CREATE TABLE user_activities (
	id INTEGER NOT NULL, 
	user_id INTEGER NOT NULL, 
	active_at DATETIME NOT NULL, 
	cycle_date DATETIME NOT NULL, 
	created_at DATETIME, 
	PRIMARY KEY (id), 
	FOREIGN KEY(user_id) REFERENCES users (id)
);
CREATE TABLE user_google_tokens (
	user_id INTEGER NOT NULL, 
	access_token TEXT NOT NULL, 
	refresh_token TEXT, 
	expires_at DATETIME, 
	created_at DATETIME, 
	updated_at DATETIME, calendar_id VARCHAR(255), 
	PRIMARY KEY (user_id), 
	FOREIGN KEY(user_id) REFERENCES users (id)
);
CREATE TABLE task_google_sync (
	user_id INTEGER NOT NULL, 
	task_id INTEGER NOT NULL, 
	google_event_id VARCHAR(512) NOT NULL, 
	created_at DATETIME, 
	updated_at DATETIME, 
	PRIMARY KEY (user_id, task_id), 
	FOREIGN KEY(user_id) REFERENCES users (id), 
	FOREIGN KEY(task_id) REFERENCES tasks (id)
);
CREATE TABLE project_google_sync (
	user_id INTEGER NOT NULL, 
	project_id INTEGER NOT NULL, 
	google_event_id VARCHAR(512) NOT NULL, 
	created_at DATETIME, 
	updated_at DATETIME, 
	PRIMARY KEY (user_id, project_id), 
	FOREIGN KEY(user_id) REFERENCES users (id), 
	FOREIGN KEY(project_id) REFERENCES projects (id)
);
CREATE TABLE event_google_sync (
	user_id INTEGER NOT NULL, 
	event_id INTEGER NOT NULL, 
	google_event_id VARCHAR(512) NOT NULL, 
	created_at DATETIME, 
	updated_at DATETIME, 
	PRIMARY KEY (user_id, event_id), 
	FOREIGN KEY(user_id) REFERENCES users (id), 
	FOREIGN KEY(event_id) REFERENCES events (id)
);
CREATE TABLE meetings (
	id INTEGER NOT NULL, 
	project_id INTEGER NOT NULL, 
	title VARCHAR NOT NULL, 
	date DATETIME NOT NULL, 
	audio_url TEXT, 
	transcript TEXT, 
	decisions JSON, 
	tasks JSON, 
	discussion_points JSON, 
	deadlines JSON, 
	created_at DATETIME, 
	updated_at DATETIME, status VARCHAR(50) DEFAULT 'pending', version_group VARCHAR(255), 
	PRIMARY KEY (id), 
	FOREIGN KEY(project_id) REFERENCES projects (id)
);
CREATE TABLE chat_messages (
                id INTEGER PRIMARY KEY AUTOINCREMENT,
                conversation_id VARCHAR(255),
                role VARCHAR(50),
                content TEXT,
                user_id INTEGER,
                created_at DATETIME,
                FOREIGN KEY(user_id) REFERENCES users(id)
            );
CREATE TABLE knowledge_items (
                id INTEGER PRIMARY KEY AUTOINCREMENT,
                title VARCHAR(255),
                project_id INTEGER,
                file_name VARCHAR(255),
                file_path TEXT,
                file_type VARCHAR(50),
                status VARCHAR(50),
                summary TEXT,
                content_text TEXT,
                metadata_json JSON,
                created_by INTEGER,
                created_at DATETIME,
                updated_at DATETIME,
                FOREIGN KEY(project_id) REFERENCES projects(id),
                FOREIGN KEY(created_by) REFERENCES users(id)
            );
/****** CORRUPTION ERROR *******/
CREATE TABLE knowledge_tags (
                id INTEGER PRIMARY KEY AUTOINCREMENT,
                knowledge_item_id INTEGER,
                name VARCHAR(100),
                FOREIGN KEY(knowledge_item_id) REFERENCES knowledge_items(id)
            );
CREATE TABLE decisions (
	id INTEGER NOT NULL, 
	meeting_id INTEGER, 
	content TEXT NOT NULL, 
	date DATETIME NOT NULL, 
	superseded BOOLEAN NOT NULL, 
	project_id INTEGER, 
	PRIMARY KEY (id), 
	FOREIGN KEY(meeting_id) REFERENCES meetings (id), 
	FOREIGN KEY(project_id) REFERENCES projects (id)
);
DELETE FROM sqlite_sequence;
CREATE UNIQUE INDEX ix_users_username ON users (username);
CREATE INDEX ix_users_id ON users (id);
CREATE UNIQUE INDEX ix_users_email ON users (email);
CREATE INDEX ix_users_full_name ON users (full_name);
CREATE INDEX ix_users_name ON users (name);
CREATE INDEX ix_projects_name ON projects (name);
CREATE INDEX ix_projects_display_status ON projects (display_status);
CREATE INDEX ix_projects_id ON projects (id);
CREATE INDEX ix_groups_name ON groups (name);
CREATE INDEX ix_groups_id ON groups (id);
CREATE INDEX ix_tasks_display_status ON tasks (display_status);
CREATE INDEX ix_tasks_name ON tasks (name);
CREATE INDEX "ix_tasks_shotID" ON tasks ("shotID");
CREATE INDEX "ix_tasks_seqID" ON tasks ("seqID");
CREATE INDEX ix_tasks_id ON tasks (id);
CREATE INDEX ix_events_title ON events (title);
CREATE INDEX ix_events_status ON events (status);
CREATE INDEX ix_events_id ON events (id);
CREATE INDEX ix_task_status_history_task_id ON task_status_history (task_id);
CREATE INDEX ix_task_status_history_id ON task_status_history (id);
CREATE INDEX ix_task_status_history_changed_at ON task_status_history (changed_at);
CREATE INDEX ix_notes_id ON notes (id);
CREATE INDEX ix_user_activities_active_at ON user_activities (active_at);
CREATE INDEX ix_user_activities_cycle_date ON user_activities (cycle_date);
CREATE INDEX ix_user_activities_id ON user_activities (id);
CREATE INDEX ix_user_activities_user_id ON user_activities (user_id);
CREATE INDEX ix_task_google_sync_google_event_id ON task_google_sync (google_event_id);
CREATE INDEX ix_project_google_sync_google_event_id ON project_google_sync (google_event_id);
CREATE INDEX ix_event_google_sync_google_event_id ON event_google_sync (google_event_id);
CREATE INDEX ix_meetings_project_id ON meetings (project_id);
CREATE INDEX ix_meetings_id ON meetings (id);
CREATE INDEX ix_meetings_title ON meetings (title);
CREATE INDEX idx_chat_messages_conversation_id ON chat_messages(conversation_id);
CREATE INDEX ix_decisions_id ON decisions (id);
CREATE INDEX ix_decisions_project_id ON decisions (project_id);
COMMIT;
