INSERT INTO meetings VALUES(2,53,'test 会議 (20260218)','2026-02-18 00:00:00.000000','X:\cg\proj\kikaku\MTG_audio\test\20260218\西品川3丁目21 #33.m4a',replace('[雑談] 山中さん遅れる。\n[雑談] 山中さん送れるってライフ行くって言ってるけど。\n[質問] 今日ですか？\n[質問] 今日ですか？\n[雑談] 今日設定できない。\n[雑談] 山中さんが15分ぐらい送れるみたいなんですけど。\n[議題] 先にサーバーって立ったの？\n[提案] サーバーは僕の方で昨日作って立ちました。\n[提案] で、立ちデザイナーとの通信も確認して携帯からリモートも一応できております。\n[提案] で、その中で具体的にどういうメッセージでどういう処理をするかをこれからです。\n[回答] ああ、じゃあ順調だって事やね、そこは。\n[回答] そこは順調です。\n[タスク] 田中さん、あの貰ってきたものちょっと預かってきたもの出してもらっていいですか？\n\n[雑談] A：これ、これさ、これはコントロールできるやつじゃないでしょ。\n[雑談] B：チップをこう。\n[雑談] A：でも3ピンだね。\n[雑談] B：あ、こっちは2ピン。こっちが3ピン。\n[雑談] A：2ピン？\n[雑談] B：こっちが3ピン。\n[質問] A：できないんじゃない？チップ入ってる感じがないよね？\n[質問] B：ないよね。\n[雑談] A：これ、楽じゃん。\n[質問] A：これ、光らした？\n[雑談] B：光らした。これで一応コントローラーでは。\n[雑談] A：うん、じゃ、ただ、その、何もない。\n[雑談] B：逆ですか？\n[雑談] A：ニューカラーに載ってない。\n[雑談] B：そうそうそう。そうなんです。\n[質問] A：光らしたら。\n[雑談] A：こいつ、熱いな。\n[タスク] A：これでリサーチはちょっといるのかな？さっき言ってたから。いるのかな？多分。\n[雑談] A：で、これを100ボルトって言ってたよね？\n[雑談] B：100ボルト。\n[雑談] A：100ボルトの日本一般の。\n[雑談] B：こっちじゃない？\n[質問] A：こっちですか？\n[雑談] B：うん、こっち。\n[質問] A：100？\n[雑談] A：100。そっちの。\n[質問] B：え、こっちですか？\n[雑談] A：あの、カウント。\n[雑談] A：で、100のフルHD、フルカラーもあるらしい。\n[質問] A：で、変わるの？\n[質問] B：変わらん。\n[雑談] A：変わらん。\n[雑談] A：あー。\n[雑談] A：これじゃだめよね？\n[雑談] A：全部一色ですか？\n[雑談] A：あー。\n[質問] A：これは指示してんの？\n[雑談] A：あの、普通のボックスから指示出してるよりかは。\n[質問] A：なんか入ってないのって、何も言えないですけど。\n[雑談] A：色が変わってってるね。\n[質問] A：できるの？\n[質問] A：光ってる色は黄色、青、紫とCMY。\n[雑談] B：CMY。\n[雑談] A：白、赤。黄色か？緑。薄黄色？黄色。ループしてない？色は。\n[質問] A：もうちょっと別の色なんか無い？\n[質問] A：点滅は？\n[雑談] A：3ピンでフラッシュにしてるよね？\n[雑談] A：2本しかない。\n[雑談] B：うん、2本しかないね。\n[質問] A：あれ？\n[質問] A：2本って言っても、データに入ってしているの1本だけです。\n[質問] A：もう1本の線は固定？\n[雑談] B：2本入ってる。2本入ってるけど、あ？違う？\n[質問] A：こっち2本しかないんだよ。\n[雑談] B：だってこれを見たら、1本、1本出て、1本また書いてないです。\n[雑談] A：で、今、ちょっと見てる。\n\n[雑談] A：もう1個、もう1個言うだけじゃないかなって思ってます。\n[雑談] A：ここは2本ある？\n[質問] A：えっと、あ、でも2本、1本しか入ってない？\n[提案] A：で、だから、あれだよね？RGBが 順番に入ってきて、こうクルクルしてるんじゃない？\n[質問] B：えっと、今見た感じ、2箇所を見たんですけど 両方とも同じ1本しか入ってないです。もう1本は真ん中、あの、素通りです。\n[雑談] A：いや、言ってるのはわかった。分かってるけど。 で、その1本で光らせてるんであるならば、電圧で変えてるよね？\n[雑談] A：電圧。 で、電圧で変えるってことは 多分 電圧で 変わるLEDはあるの？ 色が。 