\u304c\u3046\u307e\u304f\u3044\u304b\u306a\u3044\u7406\u7531\u3092\u8abf\u67fb\u3057\u3001\u6539\u5584\u7b56\u3092\u691c\u8a0e\u3059\u308b\u3002", "\u30ab\u30e1\u30e9\u306e\u8abf\u6574\u3068\u30c6\u30b9\u30c8\u3092\u7e70\u308a\u8fd4\u3059\u3053\u3068\u306b\u3064\u3044\u3066\u3001\u3069\u3053\u307e\u3067\u3084\u308b\u304b\u306e\u7dda\u5f15\u304d\u3092\u691c\u8a0e\u3059\u308b\u3002", "\u64ae\u5f71\u3057\u305f\u3082\u306e\u3092\u540c\u3058\u74b0\u5883\u3067\u64ae\u5f71\u3057\u305f\u30c6\u30b9\u30c8\u3068\u6bd4\u8f03\u3057\u3066\u3001\u3053\u3046\u306a\u3063\u305f\u3068\u63a8\u6e2c\u3055\u308c\u308b\u304f\u3089\u3044\u306e\u3053\u3068\u3092\u8a00\u3046\u3002", "\u63a8\u6e2c\u306e\u7d50\u679c\u3092\u8abf\u6574\u3057\u305f\u3089\u3069\u3046\u3044\u3046\u7d50\u679c\u304c\u5f97\u3089\u308c\u305f\u304b\u3068\u3044\u3046\u7a0b\u5ea6\u306e\u3053\u3068\u306a\u3089\u3067\u304d\u308b\u3002", "\u6bd4\u8f03\u3057\u305f\u7d50\u679c\u307e\u3067\u306e\u63a8\u6e2c\u3068\u3044\u3046\u3068\u3053\u308d\u307e\u3067\u3092\u63d0\u4f9b\u3059\u308b\u3002", "\u5ea7\u6a19\u304c\u305a\u308c\u3066\u3044\u306a\u3044\u304b\u306e\u78ba\u8a8d\u3092\u884c\u3046\u3002"]','["[review] A\uff1a3\u670813\u65e5\u306e\u5831\u544a\u306b\u5411\u3051\u3066\u3001\u5831\u544a\u3067\u304d\u308b\u3082\u306e\u3068\u3067\u304d\u306a\u3044\u3082\u306e\u3092\u533a\u5225\u3059\u308b\u3002\u7d0d\u54c1\u306b\u95a2\u3059\u308b\u554f\u984c\u3082\u78ba\u8a8d\u3059\u308b\u3002\uff082026\u5e743\u670813\u65e5\uff09", "[review] A\uff1a\u5de5\u5834\u304b\u3089\u306e\u60c5\u5831\u3092\u78ba\u8a8d\u3057\u30013\u670817\u65e5\u307e\u3067\u306b\u5fc5\u8981\u306a\u60c5\u5831\u3092\u63c3\u3048\u308b\u3002\uff082026\u5e743\u670817\u65e5\uff09", "[asset] B\uff1a\u5c0f\u9053\u5177\u68da\u306eUE5\u30d7\u30ed\u30b8\u30a7\u30af\u30c8\u63d0\u4f9b\u3092\u672c\u65e5\u5b8c\u4e86\u3057\u3001\u63d0\u51fa\u3059\u308b\u3002\uff08\u672c\u65e5\uff09", "[documentation] B\uff1a\u30b7\u30fc\u30c8\u3092\u660e\u65e5\u4f5c\u6210\u3059\u308b\u3002\uff08\u660e\u65e5\uff09", "[asset] B\uff1a\u8eca\u4e21\u30923\u670819\u65e5\u306b\u4f5c\u6210\u3059\u308b\u3002\uff082026\u5e743\u670819\u65e5\uff09", "[analysis] \u62c5\u5f53\u8005\uff1aGS\u3092\u57fa\u6e96\u3068\u3057\u305f\u5b9f\u5199\u3068\u306e\u5dee\u7570\u5206\u6790\uff08\u671f\u9650\uff1a\u672a\u5b9a\uff09", "[testing] \u62c5\u5f53\u8005\uff1a\u3044\u3064\u307e\u3067\u306b\u63d0\u51fa\u3067\u304d\u308b\u304b\u5f8c\u307b\u3069\u9023\u7d61\u3059\u308b\u3002\uff08\u671f\u9650\uff1a\u5f8c\u307b\u3069\u9023\u7d61\uff09", "[testing] \u62c5\u5f53\u8005\uff1a1\u30d4\u30af\u30bb\u30eb\u304c\u4f55cm\u304b\u3001\u4f55mm\u304b\u5358\u7d14\u8a08\u7b97\u3067\u51fa\u3059\u3002\uff08\u671f\u9650\uff1a\u672a\u5b9a\uff09", "[meeting] \u62c5\u5f53\u8005\uff1a\u5f8c\u307b\u3069\u3001\u8a08\u6e2c\u306b\u3064\u3044\u3066\u78ba\u8a8d\u3057\u3001\u9023\u7d61\u3059\u308b\u3002\uff08\u671f\u9650\uff1a\u5f8c\u307b\u3069\u9023\u7d61\uff09", "[documentation] \u62c5\u5f53\u8005\uff1a\u30d7\u30ea\u30a6\u30b9\u306e\u54c1\u8cea\u304c\u51fa\u305b\u305f\u7406\u7531\u3092\u30c9\u30ad\u30e5\u30e1\u30f3\u30c8\u5316\u3059\u308b\uff08\u671f\u9650\uff1a\u672a\u5b9a\uff09", "[documentation] \u62c5\u5f53\u8005\uff1a\u8eca\u3001\u30b7\u30fc\u30c8\u3001\u305d\u306e\u4ed6\u30a2\u30bb\u30c3\u30c8\u306e\u54c1\u8cea\u306b\u5dee\u304c\u3042\u308b\u7406\u7531\u3092\u30c9\u30ad\u30e5\u30e1\u30f3\u30c8\u5316\u3059\u308b\uff08\u671f\u9650\uff1a\u672a\u5b9a\uff09", "[testing] \u62c5\u5f53\u8005\uff1a\u691c\u8a3c\u3092\u884c\u3046\uff08\u671f\u9650\u672a\u5b9a\uff09", "[review] \u62c5\u5f53\u8005\uff1a23\u65e5\u307e\u3067\u306b\u3069\u3053\u307e\u3067\u5408\u308f\u305b\u308b\u304b\u691c\u8a0e\u3059\u308b\u3002\uff082026\u5e743\u670823\u65e5\uff09", "[meeting] \u767d\u4e95\uff1a\u5148\u65b9\u3055\u3093\u3068\u8a71\u3057\u3066\u3001\u4e8b\u60c5\u304c\u3042\u308b\u304b\u3069\u3046\u304b\u3092\u6559\u3048\u3066\u3082\u3089\u3046\uff08\u672a\u5b9a\uff09", "[review] \u767d\u4e95\uff1aPOC\u691c\u8a3c\u306e\u8ab2\u984c\u5bfe\u7b56\u3001GS\u306e\u54c1\u8cea\u539f\u56e0\u7a76\u660e\u3001\u30e1\u30c3\u30b7\u30e5\u54c1\u8cea\u539f\u56e0\u306b\u3064\u3044\u3066\u691c\u8a0e\u3059\u308b\uff08\u672a\u5b9a\uff09", "[documentation] \u62c5\u5f53\u8005\uff1a\u64ae\u5f71\u65b9\u6cd5\u306e\u9055\u3044\u3092\u4e26\u3079\u305f\u8cc7\u6599\u3092\u4f5c\u6210\u3059\u308b\uff08\u671f\u9650\u672a\u5b9a\uff09", "[documentation] A\uff1a\u3053\u306e\u74b0\u5883\u3067\u306f\u51fa\u305b\u306a\u3044\u3068\u3044\u3046\u8cc7\u6599\u3092\u4f5c\u6210\u3059\u308b\uff08\u671f\u9650\u306a\u3057\uff09", "[testing] \u62c5\u5f53\u8005\uff1a\u524d\u3005\u56de\u30d7\u30ea\u30a6\u30b9\u3068\u4eca\u56de\u30af\u30e9\u30a6\u30f3\u306e\u6bd4\u8f03\u691c\u8a3c\uff082026\u5e743\u670823\u65e5\u4ee5\u964d\uff09", "[documentation] \u62c5\u5f53\u8005\uff1a27\u65e5\u307e\u3067\u306b\u8cc7\u6599\u3092\u6e96\u5099\u3059\u308b\u3002\uff082026\u5e743\u670827\u65e5\uff09", "[\u8abf\u6574] \u62c5\u5f53\u8005\uff1a\u767d\u77f3\u3055\u3093\u3068\u5185\u5bb9\u3092\u8efd\u304f\u3059\u308a\u5408\u308f\u305b\u308b\uff08\u671f\u9650\uff1a\u4e0d\u660e\uff09", "[meeting] \u62c5\u5f53\u8005\uff1a\u5e73\u7530\u3055\u3093\u3068\u4f1a\u3063\u3066\u8a71\u3092\u3059\u308b\uff08\u6642\u671f\u672a\u5b9a\uff09", "[meeting] \u62c5\u5f53\u8005\uff1a\u30df\u30fc\u30c6\u30a3\u30f3\u30b0\u5f8c\u3001\u78ba\u8a8d\u3059\u308b\uff08\u671f\u9650\u672a\u5b9a\uff09", "[\u78ba\u8a8d] \u767d\u77f3\uff1a\u30b9\u30b1\u30b8\u30e5\u30fc\u30eb\u30b9\u30c6\u30fc\u30bf\u30b9\u306e\u78ba\u8a8d\uff08\u5f8c\u65e5\uff09", "[documentation] \u62c5\u5f53\u8005\uff1a\u30de\u30cb\u30e5\u30a2\u30eb\u7b49\u3092\u4eca\u9031\u4e2d\u306b\u6e21\u305b\u308b\u3088\u3046\u306b\u3059\u308b\u3002\uff08\u4eca\u9031\u4e2d\uff09", "[asset] \u62c5\u5f53\u8005\uff1a3\u670819\u65e5\u306b\u798f\u5ca1\u304b\u3089\u7d20\u6750\u304c\u6e21\u3055\u308c\u308b\u3002\uff082026\u5e743\u670819\u65e5\uff09", "[asset] \u62c5\u5f53\u8005\uff1a\u798f\u5ca1\u304b\u3089\u306e\u7d20\u6750\u3092\u5143\u306bGS\u3067\u7de8\u96c6\u3057\u300121\u65e5\u306e\u571f\u66dc\u306e\u671d\u307e\u3067\u306bPLI\u3092\u6e21\u305b\u308b\u3088\u3046\u306b\u3059\u308b\u3002\uff082026\u5e743\u670821\u65e5\uff09", "[meeting] \u62c5\u5f53\u8005\uff1a\u30df\u30fc\u30c6\u30a3\u30f3\u30b0\u5f8c\u3001\u793e\u5185\u78ba\u8a8d\u3092\u884c\u3044\u3001\u554f\u984c\u70b9\u304c\u3042\u308c\u3070\u6539\u3081\u3066\u9023\u7d61\u3059\u308b\uff08\u671f\u9650\u672a\u5b9a\uff09", "[documentation] \u62c5\u5f53\u8005\uff1a\u5e73\u7530\u3055\u3093\u306b\u6e21\u3059\u8cc7\u6599\u3092\u30b9\u30af\u30eb\u30a8\u30f3\u3068\u306b\u3059\u308b\u305f\u3081\u3001\u8cc7\u6599\u3092\u4fee\u6b63\u3059\u308b\uff08\u671f\u9650\u672a\u5b9a\uff09", "[investigation] \u62c5\u5f53\u8005\uff1a\u30ab\u30e1\u30e9\u30a2\u30e9\u30a4\u30e1\u30f3\u30c8\u304c\u3046\u307e\u304f\u3044\u304b\u306a\u3044\u7406\u7531\u306e\u8a73\u7d30\u306a\u8abf\u67fb\u3068\u691c\u8a3c\u3092\u884c\u3046\u3002\uff08\u671f\u9650\u672a\u5b9a\uff09", "[report] \u62c5\u5f53\u8005\uff1a\u8abf\u67fb\u7d50\u679c\u3068\u6539\u5584\u7b56\u3092\u5831\u544a\u3059\u308b\u3002\uff08\u671f\u9650\u672a\u5b9a\uff09", "[meeting] \u62c5\u5f53\u8005\uff1a\u30ab\u30e1\u30e9\u306e\u8abf\u6574\u3068\u30c6\u30b9\u30c8\u3092\u7e70\u308a\u8fd4\u3059\u3053\u3068\u306b\u3064\u3044\u3066\u3001\u3069\u3053\u307e\u3067\u3084\u308b\u304b\u306e\u7dda\u5f15\u304d\u3092\u691c\u8a0e\u3059\u308b\u305f\u3081\u306e\u4f1a\u8b70\u3092\u8a2d\u5b9a\u3059\u308b\uff08\u660e\u65e5\u307e\u3067\uff09", "[\u8cc7\u6599] A\uff1a\u691c\u8a3c\u306b\u95a2\u3059\u308b\u8cc7\u6599\u3092\u7528\u610f\u3059\u308b\u3002\uff08\u671f\u9650\u672a\u5b9a\uff09", "[meeting] A\uff1a\u767d\u77f3\u3055\u3093\u306bGS\u306e\u30ea\u30b9\u30c8\u3067\u5e0c\u671b\u306e\u7d44\u307f\u5408\u308f\u305b\u304c\u3042\u308b\u304b\u78ba\u8a8d\u3059\u308b\uff08\u5f8c\u65e5\uff09", "[documentation] \u62c5\u5f53\u8005\uff1a\u64ae\u5f71\u30de\u30cb\u30e5\u30a2\u30eb\u3092\u6700\u7d42\u7248\u306b\u4fee\u6b63\u3059\u308b\uff08\u671f\u9650\u672a\u5b9a\uff09", "[asset] \u62c5\u5f53\u8005\uff1a\u30a8\u30f3\u30b8\u30f3\u30d5\u30ed\u30f3\u30c8\u30ac\u30e9\u30b9\u5074\u306e\u6620\u50cf\u7d20\u6750\u3092\u3001\u672c\u7de8\u3068\u306f\u5225\u306b\u6e96\u5099\u3059\u308b\uff08\u671f\u9650\u672a\u5b9a\uff09", "[\u8cc7\u6599\u78ba\u8a8d] A\uff1aExcel\u306e\u5ea7\u6a19\u5358\u4f4d\u304cmm\u3067\u3042\u308b\u3068\u3044\u3046\u8a18\u8ff0\u304c\u3042\u308b\u8cc7\u6599\u3092\u78ba\u8a8d\u3059\u308b\uff08\u671f\u9650\u672a\u5b9a\uff09", "[review] \u62c5\u5f53\u8005\uff1a\u5168\u4f53\u3092\u30bb\u30c3\u30c8\u3057\u3066\u78ba\u8a8d\uff08\u671f\u9650\uff1a\u672a\u5b9a\uff09", "[testing] \u62c5\u5f53\u8005\uff1a\u767d\u77f3\u3055\u3093\u306e\u307b\u3046\u3067\u3084\u3063\u305f\u6642\u306b\u52d5\u304b\u306a\u304b\u3063\u305f\u5ea7\u6a19\u306e\u78ba\u8a8d\u3092\u884c\u3046\u3002\uff08\u671f\u9650\uff1a\u4e0d\u660e\uff09"]','["3\u670823\u65e5\u306e\u6700\u7d42\u5831\u544a\u306b\u5411\u3051\u3001GS\u306e\u54c1\u8cea\u539f\u56e0\u7a76\u660e\u3001\u30e1\u30c3\u30b7\u30e5\u54c1\u8cea\u3001\u30ab\u30e1\u30e9\u30a2\u30e9\u30a4\u30e1\u30f3\u30c8\u306e\u554f\u984c\u306a\u3069\u3001\u8907\u6570\u306e\u8ab2\u984c\u306b\u5bfe\u3059\u308b\u691c\u8a3c\u3068\u8cc7\u6599\u6e96\u5099\u304c\u5fc5\u8981\u3067\u3042\u308b\u3002", "\u524d\u63d0\u6761\u4ef6\u306e\u76f8\u9055\u306b\u3088\u308b\u5bfe\u5fdc\u306e\u56f0\u96e3\u3055\u3001\u30a2\u30bb\u30c3\u30c8\u54c1\u8cea\u306e\u3070\u3089\u3064\u304d\u3001\u30ea\u30d5\u30ec\u30af\u30b7\u30e7\u30f3\u306e\u691c\u8a3c\u65b9\u6cd5\u3001\u64ae\u5f71\u65b9\u6cd5\u306e\u9055\u3044\u306a\u3069\u304c\u8b70\u8ad6\u3055\u308c\u3066\u3044\u308b\u3002", "\u7279\u306b\u3001\u30ea\u30d5\u30ec\u30af\u30b7\u30e7\u30f3\u306e\u6570\u5024\u5316\u3001\u30d7\u30ea\u30a6\u30b9\u3068\u306e\u6bd4\u8f03\u3001\u9867\u5ba2\u3078\u306e\u8aac\u660e\u65b9\u6cd5\u3001\u6700\u7d42\u7684\u306a\u7d0d\u54c1\u7269\u306e\u30ec\u30d9\u30eb\u611f\u306a\u3069\u304c\u91cd\u8981\u306a\u691c\u8a0e\u4e8b\u9805\u3068\u306a\u3063\u3066\u3044\u308b\u3002", "\u307e\u305f\u30